import React, { useState, useEffect } from 'react';
import Input from '../Input';
import Button from '../Button';
import FileUpload from '../FileUpload';
import styles from './DesignForm.module.scss';
import { useRouter } from 'next/router';
import { toastError } from '../../lib';
import { FileRejection } from 'react-dropzone';

// Constants
const CATEGORIES = ['Floral', 'Abstract', 'Animals', 'Kids', 'Logos', 'Traditional'];
const FORMATS = ['DST', 'PES', 'EMB']; // Only these allowed
const HOOP_SIZES = ['4x4', '5x7', '6x10', '8x8', '8x12', 'Commercial'];

interface DesignFormProps {
    initialValues?: any;
    mode: 'create' | 'edit';
    onSubmit: (data: any) => Promise<void>;
    isLoading?: boolean;
}

const DesignForm: React.FC<DesignFormProps> = ({ initialValues, mode, onSubmit, isLoading = false }) => {
    const router = useRouter();
    const [errors, setErrors] = useState<Record<string, string>>({});

    // Form State
    const [title, setTitle] = useState(initialValues?.title || '');
    const [price, setPrice] = useState(initialValues?.price || '');
    const [description, setDescription] = useState(initialValues?.description || '');
    const [category, setCategory] = useState(initialValues?.category || '');
    const [stitchingCount, setStitchingCount] = useState(initialValues?.stitchingCount || '');
    const [hoopSize, setHoopSize] = useState(initialValues?.hoopSize || '');
    const [selectedFormats, setSelectedFormats] = useState<string[]>(initialValues?.selectedFormats || []);

    // Files
    const [previewImage, setPreviewImage] = useState<File[]>([]); // Logic for initial files to be added if needed
    const [designFiles, setDesignFiles] = useState<File[]>([]);

    const validate = () => {
        const newErrors: Record<string, string> = {};
        if (!title.trim()) newErrors.title = "Design name is required";
        if (!price || Number(price) <= 0) newErrors.price = "Price must be greater than zero";
        if (!category) newErrors.category = "Please select a category";
        if (!stitchingCount || Number(stitchingCount) <= 0) newErrors.stitchingCount = "Stitching count is required";
        if (!hoopSize) newErrors.hoopSize = "Please select a hoop size";
        if (selectedFormats.length === 0) newErrors.formats = "Select at least one supported format";

        // In edit mode, we might not require re-uploading files if they already exist (logic can be refined)
        // For now enforcing strictly as requested for Create
        if (mode === 'create') {
            if (previewImage.length === 0) newErrors.preview = "Preview image is mandatory";
            if (designFiles.length === 0) newErrors.files = "At least one embroidery file is required";
        }

        setErrors(newErrors);
        return Object.keys(newErrors).length === 0;
    };

    const handleFormSubmit = async (status: 'DRAFT' | 'PENDING') => {
        if (status === 'PENDING' || status === 'DRAFT' && !validate()) {
            if (Object.keys(errors).length > 0) {
                toastError("Please fix the errors before submitting");
            }
            return;
        }

        const data = {
            title,
            price,
            description,
            category,
            stitchingCount,
            hoopSize,
            selectedFormats,
            previewImage,
            designFiles,
            status
        };

        await onSubmit(data);
    };

    const toggleFormat = (format: string) => {
        setSelectedFormats(prev =>
            prev.includes(format) ? prev.filter(f => f !== format) : [...prev, format]
        );
    };

    const handleEmbroideryDrop = (files: File[], fileRejections: FileRejection[]) => {
        if (fileRejections.length > 0) {
            toastError("Invalid file type! Only .dst, .pes, .emb are allowed.");
        }
        setDesignFiles(prev => [...prev, ...files]);
    };

    return (
        <div className={styles.formGrid}>
            <div className={styles.column}>
                <section className={styles.card}>
                    <h3>Basic Information</h3>
                    <Input
                        label="Design Name"
                        placeholder="e.g. Vintage Floral Pattern"
                        value={title}
                        onChange={(e) => setTitle(e.target.value)}
                        error={errors.title}
                    />
                    <div className={styles.row}>
                        <Input
                            label="Price (Γé╣)"
                            type="number"
                            placeholder="0.00"
                            value={price}
                            onChange={(e) => setPrice(e.target.value)}
                            onWheel={(e) => (e.target as HTMLInputElement).blur()}
                            error={errors.price}
                        />
                        <div className={styles.inputWrapper}>
                            <label className={styles.label}>Category</label>
                            <select
                                className={`${styles.select} ${errors.category ? styles.hasError : ''}`}
                                value={category}
                                onChange={(e) => setCategory(e.target.value)}
                            >
                                <option value="">Select Category...</option>
                                {CATEGORIES.map(c => <option key={c} value={c}>{c}</option>)}
                            </select>
                            {errors.category && <span className={styles.errorMessage}>{errors.category}</span>}
                        </div>
                    </div>

                    <div className={styles.row}>
                        <Input
                            label="Stitching Count"
                            type="number"
                            placeholder="e.g. 15000"
                            value={stitchingCount}
                            onChange={(e) => setStitchingCount(e.target.value)}
                            onWheel={(e) => (e.target as HTMLInputElement).blur()}
                            error={errors.stitchingCount}
                        />
                        <div className={styles.inputWrapper}>
                            <label className={styles.label}>Hoop Size</label>
                            <select
                                className={`${styles.select} ${errors.hoopSize ? styles.hasError : ''}`}
                                value={hoopSize}
                                onChange={(e) => setHoopSize(e.target.value)}
                            >
                                <option value="">Select Hoop Size...</option>
                                {HOOP_SIZES.map(s => <option key={s} value={s}>{s}</option>)}
                            </select>
                            {errors.hoopSize && <span className={styles.errorMessage}>{errors.hoopSize}</span>}
                        </div>
                    </div>

                    <div className={styles.inputWrapper}>
                        <label className={styles.label}>Description (Optional)</label>
                        <textarea
                            className={styles.textarea}
                            rows={4}
                            value={description}
                            onChange={(e) => setDescription(e.target.value)}
                        />
                    </div>
                </section>

                <section className={styles.card}>
                    <h3>Technical Details</h3>
                    <label className={styles.label}>Supported Formats {errors.formats && <span className={styles.errorMessage}>({errors.formats})</span>}</label>
                    <div className={styles.tags}>
                        {FORMATS.map(fmt => (
                            <button
                                type="button"
                                key={fmt}
                                className={`${styles.tag} ${selectedFormats.includes(fmt) ? styles.activeTag : ''}`}
                                onClick={() => toggleFormat(fmt)}
                            >
                                {fmt}
                            </button>
                        ))}
                    </div>
                </section>
            </div>

            <div className={styles.column}>
                <section className={styles.card}>
                    <h3>Media & Files</h3>

                    <div className={styles.uploadSection}>
                        <label className={styles.label}>Preview Image (Mandatory)</label>
                        <FileUpload
                            onDrop={setPreviewImage}
                            files={previewImage}
                            onRemove={() => setPreviewImage([])}
                            accept={{ 'image/*': ['.jpeg', '.png', '.jpg'] }}
                            maxFiles={1}
                            preview
                        />
                        {errors.preview && <span className={styles.errorMessage}>{errors.preview}</span>}
                    </div>

                    <div className={styles.uploadSection}>
                        <label className={styles.label}>Embroidery Files</label>
                        {/* Restriction implemented here */}
                        <FileUpload
                            onDrop={handleEmbroideryDrop}
                            files={designFiles}
                            onRemove={(file) => setDesignFiles(prev => prev.filter(f => f !== file))}
                            label="Upload .dst, .pes, .emb files"
                            accept={{
                                'application/x-dst': ['.dst'],
                                'application/x-pes': ['.pes'],
                                'application/x-emb': ['.emb'],
                                // Fallback for broader acceptance if mime types are tricky, but validation logic also handles it
                                'application/octet-stream': ['.dst', '.pes', '.emb']
                            }}
                            maxFiles={5}
                        />
                        {errors.files && <span className={styles.errorMessage}>{errors.files}</span>}
                    </div>
                </section>

                <div className={styles.actions}>
                    <Button variant="secondary" onClick={() => router.push('/designs')}>
                        Cancel
                    </Button>
                    {/* Buttons could be passed or rendered here. For simplicity rendering here and exposing handlers */}
                    <Button variant="secondary" onClick={() => handleFormSubmit('DRAFT')}>Save as Draft</Button>
                    <Button variant="primary" onClick={() => handleFormSubmit('PENDING')} isLoading={isLoading}>
                        {mode === 'create' ? 'Submit for Review' : 'Update & Resubmit'}
                    </Button>
                </div>
            </div>
        </div>
    );
};

export default DesignForm;

import React, { useCallback } from 'react';
import { useDropzone } from 'react-dropzone';
import { FiUploadCloud, FiFile, FiX } from 'react-icons/fi';
import styles from './FileUpload.module.scss';
import Image from 'next/image';

import { FileRejection } from 'react-dropzone';

interface FileUploadProps {
    onDrop: (acceptedFiles: File[], fileRejections: FileRejection[]) => void;
    files: File[];
    onRemove: (file: File) => void;
    accept?: Record<string, string[]>;
    maxFiles?: number;
    label?: string;
    preview?: boolean;
}

const FileUpload: React.FC<FileUploadProps> = ({
    onDrop,
    files,
    onRemove,
    accept,
    maxFiles = 1,
    label = "Drag & drop files here, or click to select",
    preview = false
}) => {
    const { getRootProps, getInputProps, isDragActive } = useDropzone({
        onDrop,
        accept,
        maxFiles
    });

    return (
        <div className={styles.container}>
            <div
                {...getRootProps()}
                className={`${styles.dropzone} ${isDragActive ? styles.active : ''} ${files.length > 0 && maxFiles === 1 && preview ? styles.hasFile : ''}`}
            >
                <input {...getInputProps()} />

                {files.length > 0 && maxFiles === 1 && preview ? (
                    <div className={styles.previewContainer}>
                        <img
                            src={URL.createObjectURL(files[0])}
                            alt="Preview"
                            className={styles.previewImage}
                        />
                        <div className={styles.overlay}>
                            <FiUploadCloud />
                            <span>Change Image</span>
                        </div>
                    </div>
                ) : (
                    <div className={styles.placeholder}>
                        <FiUploadCloud className={styles.icon} />
                        <p>{isDragActive ? "Drop the files here..." : label}</p>
                    </div>
                )}
            </div>

            {(!maxFiles || maxFiles > 1 || !preview) && files.length > 0 && (
                <ul className={styles.fileList}>
                    {files.map((file, index) => (
                        <li key={index} className={styles.fileItem}>
                            <FiFile className={styles.fileIcon} />
                            <span className={styles.fileName}>{file.name}</span>
                            <button
                                type="button"
                                onClick={() => onRemove(file)}
                                className={styles.removeButton}
                            >
                                <FiX />
                            </button>
                        </li>
                    ))}
                </ul>
            )}
        </div>
    );
};

export default FileUpload;

import React from 'react';
import { Modal as BsModal, Button } from 'react-bootstrap';
import styles from './Modal.module.scss';

interface ModalProps {
    isOpen: boolean;
    onClose: () => void;
    title?: string;
    children: React.ReactNode;
    footer?: React.ReactNode;
}

const Modal: React.FC<ModalProps> = ({ isOpen, onClose, title, children, footer }) => {
    return (
        <BsModal
            show={isOpen}
            onHide={onClose}
            centered
            className={styles.bootstrapModal}
            contentClassName={styles.bootstrapModalContent}
        >
            {title && (
                <BsModal.Header closeButton>
                    <BsModal.Title className={styles.title}>{title}</BsModal.Title>
                </BsModal.Header>
            )}
            <BsModal.Body className={styles.content}>
                {children}
            </BsModal.Body>
            {footer && (
                <BsModal.Footer className={styles.footer}>
                    {footer}
                </BsModal.Footer>
            )}
        </BsModal>
    );
};

export default Modal;

import React, { createContext, useContext, useState, useEffect } from 'react';
import { useRouter } from 'next/router';
import { toastSuccess, toastError } from '../lib';
import { auth, googleProvider } from '../lib/firebase';
import { signInWithPopup, onAuthStateChanged, User as FirebaseUser } from 'firebase/auth';

// Mock User Type
interface User {
    id: string;
    name: string;
    email: string;
    role: 'designer';
    password?: string;
}

interface AuthContextType {
    user: User | null;
    login: (email: string, password: string) => Promise<void>;
    register: (name: string, email: string, password: string) => Promise<void>;
    loginWithGoogle: () => Promise<void>;
    logout: () => void;
    isLoading: boolean;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export const AuthProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
    const [user, setUser] = useState<User | null>(null);
    const [isLoading, setIsLoading] = useState(true);
    const router = useRouter();

    useEffect(() => {
        const unsubscribe = onAuthStateChanged(auth, (firebaseUser) => {
            if (firebaseUser) {
                const userData: User = {
                    id: firebaseUser.uid,
                    name: firebaseUser.displayName || 'User',
                    email: firebaseUser.email || '',
                    role: 'designer'
                };
                setUser(userData);
                localStorage.setItem('designer_user', JSON.stringify(userData));
            } else {
                const storedUser = localStorage.getItem('designer_user');
                if (storedUser) {
                    setUser(JSON.parse(storedUser));
                }
            }
            setIsLoading(false);
        });

        return () => unsubscribe();
    }, []);

    const login = async (email: string, password: string) => {
        setIsLoading(true);
        // Simulate API
        await new Promise((resolve) => setTimeout(resolve, 1000));

        // Get registered users from local storage
        const registeredUsers = JSON.parse(localStorage.getItem('registered_users') || '[]');
        const foundUser = registeredUsers.find((u: User) => u.email === email);

        if (foundUser) {
            if (foundUser.password && foundUser.password !== password) {
                toastError('Incorrect password.');
                setIsLoading(false);
                return;
            }

            setUser(foundUser);
            localStorage.setItem('designer_user', JSON.stringify(foundUser));
            toastSuccess('Logged in successfully!');
            router.push('/');
        } else {
            toastError('User not found. Please register first.');
        }
        setIsLoading(false);
    };

    const register = async (name: string, email: string, password: string) => {
        setIsLoading(true);
        // Simulate API
        await new Promise((resolve) => setTimeout(resolve, 1000));

        // Get registered users
        const registeredUsers = JSON.parse(localStorage.getItem('registered_users') || '[]');

        // Check if already registered
        if (registeredUsers.some((u: User) => u.email === email)) {
            toastError('Email already registered. Please login.');
            setIsLoading(false);
            return;
        }

        const newUser: User = {
            id: Date.now().toString(),
            name,
            email,
            role: 'designer',
            password
        };

        // Save new user
        localStorage.setItem('registered_users', JSON.stringify([...registeredUsers, newUser]));

        // Auto login
        setUser(newUser);
        localStorage.setItem('designer_user', JSON.stringify(newUser));

        toastSuccess('Registration successful! Welcome.');
        router.push('/');
        setIsLoading(false);
    };

    const loginWithGoogle = async () => {
        setIsLoading(true);
        try {
            const result = await signInWithPopup(auth, googleProvider);
            const firebaseUser = result.user;

            const userData: User = {
                id: firebaseUser.uid,
                name: firebaseUser.displayName || 'User',
                email: firebaseUser.email || '',
                role: 'designer'
            };

            setUser(userData);
            localStorage.setItem('designer_user', JSON.stringify(userData));
            toastSuccess('Logged in with Google successfully!');
            router.push('/');
        } catch (error: any) {
            console.error(error);
            toastError(error.message || 'Google Login failed.');
        } finally {
            setIsLoading(false);
        }
    };

    const logout = async () => {
        try {
            await auth.signOut();
            setUser(null);
            localStorage.removeItem('designer_user');
            toastSuccess('Logged out successfully.');
            router.push('/login');
        } catch (error: any) {
            toastError('Error during logout.');
        }
    };

    return (
        <AuthContext.Provider value={{ user, login, register, loginWithGoogle, logout, isLoading }}>
            {children}
        </AuthContext.Provider>
    );
};

export const useAuth = () => {
    const context = useContext(AuthContext);
    if (context === undefined) {
        throw new Error('useAuth must be used within an AuthProvider');
    }
    return context;
};

import type { AppProps } from 'next/app';
import { AuthProvider } from '../context/AuthContext';
import { Toaster } from 'react-hot-toast';
import 'bootstrap/dist/css/bootstrap.min.css';
import '../styles/globals.scss';
import '../styles/nprogress.scss'; // Import custom nprogress styles
import { useEffect, useState } from 'react';
import { useRouter } from 'next/router';
import NProgress from 'nprogress';

// Configure NProgress (optional)
NProgress.configure({ showSpinner: false });

export default function App({ Component, pageProps }: AppProps) {
  const router = useRouter();

  useEffect(() => {
    const handleStart = () => {
      NProgress.start();
    };

    const handleComplete = () => {
      NProgress.done();
    };

    const handleError = () => {
      NProgress.done();
    };

    router.events.on('routeChangeStart', handleStart);
    router.events.on('routeChangeComplete', handleComplete);
    router.events.on('routeChangeError', handleError);

    return () => {
      router.events.off('routeChangeStart', handleStart);
      router.events.off('routeChangeComplete', handleComplete);
      router.events.off('routeChangeError', handleError);
    };
  }, [router]);

  return (
    <AuthProvider>
      <Toaster position="top-right" />
      {/* {loading && <GlobalLoader />} */}
      <Component {...pageProps} />
    </AuthProvider>
  );
}

